const express = require('express');
const { createProxyMiddleware } = require('http-proxy-middleware');

const app = express();
const PORT = process.env.PORT || 3000;

// Parse JSON bodies
app.use(express.json());

// Get environment variables
const PREMBLY_APP_ID = process.env.PREMBLY_APP_ID;
const PREMBLY_API_KEY = process.env.PREMBLY_API_KEY;

// Validate environment variables
if (!PREMBLY_APP_ID || !PREMBLY_API_KEY) {
  console.error('ERROR: PREMBLY_APP_ID and PREMBLY_API_KEY environment variables are required');
  process.exit(1);
}

// Create proxy middleware for Prembly API
const premblyProxy = createProxyMiddleware({
  target: 'https://api.prembly.com',
  changeOrigin: true,
  pathRewrite: {
    '^/api/prembly': '', // Remove /api/prembly prefix when forwarding
  },
  onProxyReq: (proxyReq, req, res) => {
    // Inject Prembly authentication headers
    proxyReq.setHeader('app-id', PREMBLY_APP_ID);
    proxyReq.setHeader('x-api-key', PREMBLY_API_KEY);
  },
  onError: (err, req, res) => {
    console.error('Proxy error:', err.message);
    res.status(500).json({ 
      error: 'Proxy Error',
      message: 'Failed to proxy request to Prembly API'
    });
  }
});

// Proxy all requests to /api/prembly/* to Prembly API
app.use('/api/prembly', premblyProxy);

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Start server
app.listen(PORT, () => {
  console.log(`Prembly proxy server running on port ${PORT}`);
  console.log(`Proxying requests from /api/prembly/* to https://api.prembly.com`);
});

